import React, { createContext, useContext, useState, useEffect } from 'react';

export interface User {
  id: number;
  name: string;
  email: string;
  role: 'teacher' | 'student';
  avatar?: string;
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  login: (data: { user: User; token: string }) => void;
  logout: () => void;
  updateUser: (newUser: Partial<User>) => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  token: null,
  login: () => {},
  logout: () => {},
  updateUser: () => {},
  isAuthenticated: false,
});

export const useAuth = () => useContext(AuthContext);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(() => {
    const storedUser = localStorage.getItem('user');
    return storedUser ? JSON.parse(storedUser) : null;
  });

  const [token, setToken] = useState<string | null>(() => {
    return localStorage.getItem('token');
  });

  useEffect(() => {
    if (token) localStorage.setItem('token', token);
    if (user)  localStorage.setItem('user', JSON.stringify(user));
  }, [token, user]);

  const login = (data: { user: User; token: string }) => {
    setUser(data.user);
    setToken(data.token);
  };

  const logout = () => {
    setUser(null);
    setToken(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  };

  const updateUser = (newUser: Partial<User>) => {
    setUser(prev => prev ? { ...prev, ...newUser } : null);
  };

  return (
    <AuthContext.Provider value={{ user, token, login, logout, updateUser, isAuthenticated: !!token }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';

type Mode = 'light' | 'dark';
type ThemeColor = 'blue' | 'purple' | 'emerald' | 'rose' | 'amber';

interface ThemeContextType {
  mode: Mode;
  themeColor: ThemeColor;
  setMode: (mode: Mode) => void;
  setThemeColor: (color: ThemeColor) => void;
  toggleMode: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [mode, setMode] = useState<Mode>(() => {
    const savedMode = localStorage.getItem('theme-mode');
    if (savedMode === 'light' || savedMode === 'dark') return savedMode;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  const [themeColor, setThemeColor] = useState<ThemeColor>(() => {
    const savedColor = localStorage.getItem('theme-color');
    if (['blue', 'purple', 'emerald', 'rose', 'amber'].includes(savedColor as string)) {
      return savedColor as ThemeColor;
    }
    return 'blue';
  });

  useEffect(() => {
    const root = window.document.documentElement;

    // Remove old classes
    root.classList.remove('light', 'dark');
    root.classList.remove('theme-blue', 'theme-purple', 'theme-emerald', 'theme-rose', 'theme-amber');

    // Add new classes
    root.classList.add(mode);
    root.classList.add(`theme-${themeColor}`);

    // Update local storage
    localStorage.setItem('theme-mode', mode);
    localStorage.setItem('theme-color', themeColor);
  }, [mode, themeColor]);

  const toggleMode = () => {
    setMode(prev => (prev === 'light' ? 'dark' : 'light'));
  };

  return (
    <ThemeContext.Provider value={{ mode, themeColor, setMode, setThemeColor, toggleMode }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

